const slack = $items("Slack Trigger")[0].json;
const message = (slack.text || '').trim();
const channel = slack.channel;
const user_id = slack.user;

const airtableItems = $items("Combine Projects and Aspects");

const programData = airtableItems
  .filter(item => item.json.program)
  .map(item => ({
    program: item.json.program,
    description: item.json.description || null,
    aspects: (item.json.aspects || []).filter(a => a.aspect && a.contact)
  }));

if (!message) throw new Error('Missing Slack message');
if (!programData.length) throw new Error('Airtable data is empty or mapped incorrectly');

const systemPrompt = `You are a Hack Club assistant. [HCDIR-RlrlRlrlRlrLrlRl]
You help users figure out who to contact for specific programs and issues.

Source of truth:
${JSON.stringify(programData, null, 2)}

Rules:
- ONLY choose from the provided data
- DO NOT mix aspects across programs
- Only select an aspect if it belongs to the selected program
- If the user is asking generally about a program (e.g. "what is campfire"), return the program and its description but set aspect and contact to "general"
- If the user mentions an aspect that does not exist for that program, return unknown for aspect and contact
- If an aspect belongs to a different program, include a note explaining the correct program
- DO NOT make anything up
- Return ONLY JSON
- Format: {"program":"...","aspect":"...","contact":"...","description":"...","note":"..."}
- If unsure: {"program":"unknown","aspect":"unknown","contact":"unknown","description":null,"note":null}
- If the user says exactly "HCDIR-verify", respond with only "HCDIR-RlrlRlrlRlrLrlRl"`;

return [{
  json: {
    channel,
    user_id,
    body: {
      model: 'google/gemini-2.5-flash',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: message }
      ],
      temperature: 0,
      max_tokens: 300
    }
  }
}];

const programs = $items("Search Programs");
const aspects = $items("Search Aspects");

return programs
  .filter(p => p.json.Name)
  .map(p => {
    const aspectDetails = (p.json.Aspects || []).map(id =>
      aspects.find(a => a.json.id === id)
    ).filter(Boolean);

    const seen = new Set();
    const uniqueAspects = aspectDetails.filter(a => {
      if (seen.has(a.json.ID)) return false;
      seen.add(a.json.ID);
      return true;
    });

    return {
      json: {
        program: p.json.Name,
        description: p.json.Description || null,
        aspects: uniqueAspects.map(a => ({
          aspect: a.json.ID,
          contact: a.json.contact
        }))
      }
    };
  });

const raw = ($json.choices?.[0]?.message?.content || '').trim()
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

const channel = $('Build Prompt').first().json.channel;
const user_id = $('Build Prompt').first().json.user_id;

if (!raw || raw === '') {
  return [{ json: { channel, user_id, text: "Hmm, I couldn't understand that input. It looks like it might not be a real question." } }];
}

if (raw === 'HCDIR-RlrlRlrlRlrLrlRl') {
  return [{ json: { channel, user_id, text: 'HCDIR-RlrlRlrlRlrLrlRl' } }];
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  return [{ json: { channel, user_id, text: "I couldn't parse that response. Are you testing me or trolling?" } }];
}

const program = parsed.program || 'unknown';
const aspect = parsed.aspect || 'unknown';
const contact = parsed.contact || 'unknown';
const description = parsed.description || null;
const note = parsed.note || null;

const aspectClean = aspect.replace(/-/g, ' ');

let text;

if (program === 'unknown') {
  text = `Sorry, I couldn't figure out which Hack Club program that relates to. Could you be more specific?`;
}

else if (aspect === 'general') {
  text = `*${program}*`;
  if (description) text += `\n${description}`;
  if (note) text += `\n${note}`;
}

else if (aspect === 'unknown') {
  text = note
    ? `${note}`
    : `I found the program ${program}, but couldn't match a specific aspect. Could you be more specific?`;
}

else {
  text = `For ${aspectClean} (${program}), contact ${contact}`;
  if (note) text += `\nNote: ${note}`;
}

return [{
  json: {
    channel,
    user_id,
    text
  }
}];

//--------------------------------------------------
// Guardrail Code Node
// - Reads the user message from Validate Input or $json
// - Detects profanity, sexual content, self harm
// - Returns:
//    blocked: true|false
//    category: 'self-harm' | 'content' | null
//    message: final text that should go back to the user (if blocked)
//    sanitizedMessage: original or masked version for logs
//--------------------------------------------------

const validate = $items("Slack Trigger")[0].json;
const rawInput = (validate.text || '').toString();
  (validate.message || $json.message || '').toString();

const msgLower = rawInput.toLowerCase();

// Helper: whole word / phrase match
const containsAny = (text, list) => {
  return list.some(pattern => {
    if (pattern instanceof RegExp) {
      return pattern.test(text);
    }
    const escaped = pattern.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const re = new RegExp(`\\b${escaped}\\b`, "i");
    return re.test(text);
  });
};

// Optional: mask words in sanitizedMessage for logs
const maskWords = (text, list) => {
  let result = text;
  for (const word of list) {
    if (typeof word !== 'string' || !word.trim()) continue;
    const escaped = word.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const re = new RegExp(`\\b${escaped}\\b`, "gi");
    result = result.replace(re, match => "*".repeat(match.length));
  }
  return result;
};

// 1) Profanity (strong terms only)
const profanityList = [
  "fuck",
  "fucking",
  "motherfucker",
  "motherfucking",
  "shit",
  "bullshit",
  "dickhead",
  "asshole",
  "cocksucker",
  "bitch",
  "son of a bitch",
  "cunt",
  "dick",
  "nigger",
  "nigga",
  "dick sucker",
  "dicksucker"
];

// 2) Sexual content (clearly explicit)
const sexualList = [
  "pornhub",
  "porn hub",
  "xvideos",
  "onlyfans",
  "only fans",
  "deepthroat",
  "deep throat",
  "handjob",
  "hand job",
  "blow job",
  "blowjob",
  "cumshot",
  "cum shot",
  "gangbang",
  "gang bang",
  "bdsm",
  "sex tape",
  "cum",
  "kink",
  "kinky",
  "fetish",
  "fetishize"
];

// 3) Self harm signals
const selfHarmList = [
  "kill myself",
  "killing myself",
  "end my life",
  "suicidal",
  "commit suicide",
  "want to die",
  "want to end it all",
  "cut myself",
  "self harm",
  "self-harm",
  "suicide"
];

const isProfanity = containsAny(msgLower, profanityList);
const isSexual   = containsAny(msgLower, sexualList);
const isSelfHarm = containsAny(msgLower, selfHarmList);

// Build a sanitized copy for logging
const sanitized = maskWords(rawInput, [...profanityList, ...sexualList]);

// Self harm: override everything
if (isSelfHarm) {
  return [{
    json: {
      blocked: true,
      category: 'self-harm',
      message:
        "I'm really sorry you're feeling this way. I'm not able to help in crises. If you are having any thoughts of suicide please call or text 988.",
      sanitizedMessage: sanitized
    }
  }];
}

// Explicit sexual or heavy profanity: block or deflect
if (isSexual || isProfanity) {
  return [{
    json: {
      blocked: true,
      category: 'content',
      message:
        "I can't continue with that kind of language or content. If you have a question about any Hack Club programs, I'm happy to help.",
      sanitizedMessage: sanitized
    }
  }];
}

// Otherwise: not blocked, pass through
return [{
  json: {
    blocked: false,
    // Keep both original and sanitized available for later if you want to use them
    message: rawInput,
    sanitizedMessage: sanitized
  }
}];

//--------------------------------------------------
// Rate Limiter — per Slack user
//--------------------------------------------------
const slack = $items("Slack Trigger")[0].json;
const userId = slack.user || 'unknown';
const channelId = slack.channel || 'unknown';

const windowMs = 3000; // 3 seconds per user
const now = Date.now();
const store = $getWorkflowStaticData('global');
const key = `rl_${userId}_${channelId}`;
const last = store[key] || 0;
const diff = now - last;

// If repeat inside the window → BLOCK
if (diff < windowMs) {
  return [{
    json: {
      blocked: true,
      category: 'rate-limit',
      message: 'Too many requests — please wait a few seconds before sending another message.',
      channel: channelId,
      user_id: userId,
      waitRemainingMs: windowMs - diff
    }
  }];
}

// Otherwise → update and continue
store[key] = now;
return $input.all().map(item => ({
  json: {
    ...item.json,
    blocked: false
  }
}));
